    T res = 0;

    if (l > r) return res;

    REP(i, l-1) res += vec[i];

    REP(i, l, r+1) res += a*i;

    REP(i, r+1) res += vec[i];

    return res;

}



template<typename T>

struct BIT{

    vector<T> bit;

    BIT(int n):bit(n+1){};

    void update(int p,T x){

        while(p<SZ(bit)){

            bit[p]+=x;

            p+=p&-p;

        }

    }

    T query(int p){

        T s=0;

        while(p>0){

            s+=bit[p];

            p-=p&-p;

        }

        return s;

    }

    T sum(int l,int r){

        return query(r)-query(l-1);

    }

};





